const rawText = $json.output[0].content[0].text;
const cleanText = rawText.replace(/```json/g, '').replace(/```/g, '').trim();
const data = JSON.parse(cleanText);

const stage = String(data.funnel_stage || '').toUpperCase();
const action = String(data.suggested_action || '').toLowerCase();
const objections = String(data.objections || '').toLowerCase();
const profile = String(data.profile_summary || '').toLowerCase();
const needs = String(data.needs_summary || '').trim();

const importantStages = new Set(['DECISION', 'EVALUACION']);
const importantActions = new Set(['agendar_reunion', 'derivar_especialista']);
const lowStages = new Set(['SIN_CLASIFICAR', 'DESCUBRIMIENTO']);
const trivialObjections = ['ninguna detectada', 'ninguna', 'sin objec', 'no detectada'];

const hasRealObjections = objections.trim() && !trivialObjections.some((p) => objections.includes(p));
const hasCommercialProfile = ['b2b', 'b2c', 'presupuesto', 'capital', 'urgente', 'alta prioridad'].some((s) => profile.includes(s));

let isImportant = false;
if (stage === 'DECISION') isImportant = true;
else if (importantActions.has(action)) isImportant = true;
else if (importantStages.has(stage) && action !== 'enviar_material_educativo') isImportant = true;
else if (hasRealObjections && !lowStages.has(stage)) isImportant = true;
else if (hasCommercialProfile && importantStages.has(stage)) isImportant = true;

if (action === 'enviar_material_educativo' && lowStages.has(stage) && !hasRealObjections) isImportant = false;
if (needs.length < 24 && lowStages.has(stage)) isImportant = false;

return {
  json: {
    ...data,
    session_id: $('Edit Fields').first().json.session.id,
    is_important: isImportant,
  }
};

