=={{ JSON.stringify({
  session: { id: $json.body.session?.id ?? $execution.id },
  message: {
    content: (function(raw) {
      if (raw == null) return '';
      if (typeof raw === 'string') return raw.trim();
      if (typeof raw === 'number' || typeof raw === 'boolean') return String(raw);
      if (Array.isArray(raw)) {
        return raw.map(item => {
          if (typeof item === 'string') return item;
          if (item && typeof item === 'object') return item.text ?? item.content ?? '';
          return '';
        }).filter(Boolean).join('\n').trim();
      }
      if (typeof raw === 'object') {
        if (typeof raw.content === 'string') return raw.content.trim();
        if (Array.isArray(raw.content)) {
          return raw.content.map(b => (b && typeof b === 'object' ? (b.text ?? '') : b)).filter(Boolean).join('\n').trim();
        }
        if (typeof raw.text === 'string') return raw.text.trim();
      }
      return '';
    })($json.body.message)
  },
  history: $json.body.history ?? [],
  conversation: $json.body.conversation ?? {},
  crm: $json.body.crm ?? {},
  memory: $json.body.memory ?? {}
}) }}

